import { useState } from "react";
import "./TodoApp.css";

export function TodoApp() {
    // 1. state เก็บลิสต์งานทั้งหมด (เริ่มต้นเป็น array ว่าง)
    type Todo = {
        text: string;
        done: boolean;
    };

    const [todos, setTodos] = useState<Todo[]>([]);

    // 2. state เก็บข้อความที่กำลังพิมพ์ในช่อง input
    const [text, setText] = useState("");

    // 3. ฟังก์ชันเพิ่มงานใหม่
    function addTodo() {
        if (text === "") return;
        setTodos([...todos, { text: text, done: false }]);  // 👈 สร้าง object
        setText("");
    }

    function deleteTodo(indexToDelete: number) {
        setTodos(todos.filter((_, index) => index !== indexToDelete));
    }

    function toggleTodo(indexToToggle: number) {
        setTodos(
            todos.map((todo, index) =>
                index === indexToToggle ? { ...todo, done: !todo.done } : todo
            )
        );
    }


    return (
        <div className="todo-app">
            <h2>📝 Todo List ของฉัน</h2>

            <input
                className="todo-input"
                value={text}
                onChange={(e) => setText(e.target.value)}
                placeholder="พิมพ์งานที่ต้องทำ..."
            />
            <button type="button" className="todo-add-btn" onClick={addTodo}>
                เพิ่ม
            </button>

            <ul className="todo-list">
                {todos.map((todo, index) => (
                    <li key={index} className="todo-item">
                        <label style={{ textDecoration: todo.done ? "line-through" : "none" }}>
                            <input
                                type="checkbox"
                                checked={todo.done}
                                onChange={() => toggleTodo(index)}
                            />
                            {todo.text}
                        </label>
                        <button
                            type="button"
                            className="todo-delete-btn"
                            onClick={() => deleteTodo(index)}
                        >
                            ลบ
                        </button>
                    </li>

                ))}
            </ul>

            <p>ตอนนี้มีงานทั้งหมด: {todos.length} อัน</p>
        </div>
    );

}

