import { useState, useEffect } from "react";
import "./TodoApp.css";
import { TodoItem } from "./TodoItem";


export function TodoApp() {
    // 1. state เก็บลิสต์งานทั้งหมด (เริ่มต้นเป็น array ว่าง)
    type Todo = {
        text: string;
        done: boolean;
    };

    const [todos, setTodos] = useState<Todo[]>(() => {
        const saved = localStorage.getItem("my-todos");
        return saved ? JSON.parse(saved) : [];
    });


    // 2. state เก็บข้อความที่กำลังพิมพ์ในช่อง input
    const [text, setText] = useState("");

    const [filter, setFilter] = useState<"all" | "active" | "done">("all");

    const visibleTodos = todos.filter((todo) => {
        if (filter === "active") return !todo.done;   // เอาเฉพาะที่ยังไม่เสร็จ
        if (filter === "done") return todo.done;      // เอาเฉพาะที่เสร็จแล้ว
        return true;                                  // "all" = เอาทั้งหมด
    });



    useEffect(() => {
        localStorage.setItem("my-todos", JSON.stringify(todos));
    }, [todos]);


    // 3. ฟังก์ชันเพิ่มงานใหม่
    function addTodo() {
        if (text === "") return;
        setTodos([...todos, { text: text, done: false }]);  // 👈 สร้าง object
        setText("");
    }

    function deleteTodo(indexToDelete: number) {
        setTodos(todos.filter((_, index) => index !== indexToDelete));
    }

    function toggleTodo(indexToToggle: number) {
        setTodos(
            todos.map((todo, index) =>
                index === indexToToggle ? { ...todo, done: !todo.done } : todo
            )
        );
    }


    return (
        <div className="todo-app">
            <h2>📝 Todo List ของฉัน</h2>

            <input
                className="todo-input"
                value={text}
                onChange={(e) => setText(e.target.value)}
                placeholder="พิมพ์งานที่ต้องทำ..."
            />
            <button type="button" className="todo-add-btn" onClick={addTodo}>
                เพิ่ม
            </button>

            <div className="filter-bar">
                <button type="button" onClick={() => setFilter("all")}>ทั้งหมด</button>
                <button type="button" onClick={() => setFilter("active")}>ยังไม่เสร็จ</button>
                <button type="button" onClick={() => setFilter("done")}>เสร็จแล้ว</button>
            </div>


            <ul className="todo-list">
                {visibleTodos.map((todo, index) => (
                    <TodoItem
                        key={index}
                        todo={todo}
                        onToggle={() => toggleTodo(index)}
                        onDelete={() => deleteTodo(index)}
                    />
                ))}

            </ul>

            <p>ตอนนี้มีงานทั้งหมด: {todos.length} อัน</p>
        </div>
    );

}

content.text:
โค้ดคุณเป๊ะมากครับ! ตอนนี้เราจะแก้ bug ที่ index ไม่ตรงกันตอนกรอง

---

# 📚 บทที่ 12: ใช้ `id` เฉพาะตัว (แก้ bug ให้ถูกต้อง)

## ทำไม index ถึงพัง?

เพราะ `index` คือ "ลำดับที่ในลิสต์ที่เห็นตอนนั้น" ซึ่ง**เปลี่ยนได้** — พอกรอง, ลบ, หรือสลับ ลำดับก็เพี้ยน ทำให้กดผิดตัว

**ทางแก้:** ให้แต่ละงานมี **`id` ติดตัวถาวร** ไม่เปลี่ยนไม่ว่าจะกรองหรือลบ แล้วใช้ `id` อ้างอิงแทน index

---

## ✋ แบบฝึกหัด (4 จุด) ใน [src/TodoApp.tsx](src/TodoApp.tsx)

### ขั้นที่ 1 — เพิ่ม `id` ใน type `Todo`

```tsx
type Todo = {
  id: number;        // 👈 เพิ่มบรรทัดนี้
  text: string;
  done: boolean;
};
```

### ขั้นที่ 2 — สร้าง `id` ตอนเพิ่มงานใหม่ (แก้ `addTodo`)

```tsx
function addTodo() {
  if (text === "") return;
  setTodos([...todos, { id: Date.now(), text: text, done: false }]);
  setText("");
}
```

### ขั้นที่ 3 — แก้ `deleteTodo` และ `toggleTodo` ให้รับ `id`

```tsx
function deleteTodo(idToDelete: number) {
  setTodos(todos.filter((todo) => todo.id !== idToDelete));
}

function toggleTodo(idToToggle: number) {
  setTodos(
    todos.map((todo) =>
      todo.id === idToToggle ? { ...todo, done: !todo.done } : todo
    )
  );
}
```

### ขั้นที่ 4 — แก้ตรง `.map()` ใน JSX ให้ใช้ `todo.id`

```tsx
{visibleTodos.map((todo) => (
  <TodoItem
    key={todo.id}
    todo={todo}
    onToggle={() => toggleTodo(todo.id)}
    onDelete={() => deleteTodo(todo.id)}
  />
))}
```

> สังเกตว่าเราไม่ต้องใช้ `index` แล้ว เอาออกได้เลย (`(todo) =>` แทน `(todo, index) =>`)

---

**เป้าหมาย:** ลองกรอง "ยังไม่เสร็จ" แล้วกดติ๊ก/ลบ → ตอนนี้โดนถูกตัวแล้ว! bug หายแล้ว ✅

## 💡 อธิบายของใหม่

**1. `Date.now()` — สร้าง id ที่ไม่ซ้ำ**
- คืนค่าเป็นตัวเลขเวลาปัจจุบัน (มิลลิวินาที) เช่น `1718000000123`
- แต่ละครั้งที่เพิ่มงาน เวลาต่างกัน → id ไม่ซ้ำ ใช้เป็น id ง่ายๆ ได้ดี
- (ในงานจริงที่มี database มักใช้ id จาก server หรือ `crypto.randomUUID()` แต่ `Date.now()` พอสำหรับแอปเล็ก)

**2. อ้างอิงด้วย `id` แทน `index` — ทนทานกว่ามาก**
```tsx
// เดิม (เปราะ): index เปลี่ยนตามตำแหน่ง
todos.filter((_, index) => index !== indexToDelete)

// ใหม่ (ทน): id ติดตัวถาวร ไม่เปลี่ยน
todos.filter((todo) => todo.id !== idToDelete)
```
ตอนนี้ไม่ว่าจะกรอง เรียงใหม่ หรือลบยังไง การอ้างอิงก็ยังถูกตัวเสมอ

---

## ⚠️ หมายเหตุเล็กน้อย (ข้อมูลเก่าใน localStorage)

ถ้าคุณเคยเพิ่มงานไว้ก่อนหน้านี้ ข้อมูลเก่าใน localStorage จะ**ยังไม่มี `id`** (เพราะตอนนั้นยังไม่มี field นี้) อาจทำให้ id เป็น `undefined`

วิธีล้าง: เปิดเว็บแล้วกด **F12 → Console** พิมพ์:
```js
localStorage.removeItem("my-todos")
```
แล้วกด Enter, รีเฟรช — เริ่มใหม่สะอาดๆ (หรือกดลบงานเก่าทิ้งทีละอันก็ได้)

---

ลองทำดูครับ! ทำเสร็จแล้วเทสต์ว่ากรองแล้วกดติ๊ก/ลบถูกตัวไหม 🎯

เสร็จแล้วบอกผม — ตอนนี้แอป Todo ของคุณ **สมบูรณ์แบบและถูกต้องระดับมืออาชีพ** แล้วครับ 🏆

จากนี้ผมแนะนำ 2 ทาง:
1. **📋 สรุปทบทวนทั้งหมด** — รวบทุก Hook/concept ที่เรียนมา 12 บท เป็นชีตสรุป
2. **🚀 ต่อยอด** — เรียน React Router (ทำหลายหน้า) หรือ เรียกข้อมูลจาก API จริง

อยากไปทางไหนบอกได้เลยครับ 😊

