import { StrictMode } from "react";
import { createRoot } from "react-dom/client";
import { BrowserRouter, Routes, Route, Link } from "react-router-dom";
import "./index.css";
import { Home } from "./Home";
import { About } from "./About";
import { TodoApp } from "./TodoApp";

createRoot(document.getElementById("root")!).render(
  <StrictMode>
    <BrowserRouter>
      {/* แถบเมนู แสดงทุกหน้า */}
      <nav style={{ display: "flex", gap: 16, padding: 16 }}>
        <Link to="/">หน้าแรก</Link>
        <Link to="/todos">งานของฉัน</Link>
        <Link to="/about">เกี่ยวกับ</Link>
      </nav>

      {/* ตรงนี้จะสลับเนื้อหาตาม URL */}
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/todos" element={<TodoApp />} />
        <Route path="/about" element={<About />} />
      </Routes>
    </BrowserRouter>
  </StrictMode>
);

content.text:
ไปต่อส่วนที่เจ๋งสุดเลยครับ! **`useParams`** — ทำหน้าที่แสดงรายละเอียดเฉพาะตัว เช่น `/todos/5` แสดงงาน id 5 เท่านั้น 🎯

นี่คือหัวใจของเว็บที่มีหน้า "รายละเอียด" ทุกชนิด (สินค้า, โพสต์, โปรไฟล์ ฯลฯ)

---

# 📚 บทที่ 15: หน้ารายละเอียดด้วย `useParams`

## แนวคิด: ใส่ "ตัวแปร" ใน URL

แทนที่จะสร้าง route แยกทุกงาน (`/todos/1`, `/todos/2`, ... เป็นพันอัน) เราเขียน route เดียวที่มี **ช่องตัวแปร**:

```
/todos/:id
        ↑ จุดที่เปลี่ยนได้ — :id คือ "ช่องว่าง" รับค่าอะไรก็ได้
```

พอ URL เป็น `/todos/5` → Router จับได้ว่า `id = 5` แล้วเราเอา `5` ไปหางานที่ตรงมาแสดง

---

## ✋ แบบฝึกหัด — 3 จุด

### ขั้นที่ 1 — สร้างหน้ารายละเอียด: ไฟล์ `src/TodoDetail.tsx`

```tsx
import { useParams, Link } from "react-router-dom";

type Todo = {
  id: number;
  text: string;
  done: boolean;
};

export function TodoDetail() {
  // 1. ดึง id ออกจาก URL
  const { id } = useParams();

  // 2. โหลด todos จาก localStorage แล้วหาตัวที่ id ตรง
  const saved = localStorage.getItem("my-todos");
  const todos: Todo[] = saved ? JSON.parse(saved) : [];
  const todo = todos.find((t) => t.id === Number(id));

  // 3. ถ้าหาไม่เจอ
  if (!todo) {
    return (
      <div style={{ padding: 20 }}>
        <h1>ไม่พบงานนี้ 🤔</h1>
        <Link to="/todos">← กลับไปลิสต์งาน</Link>
      </div>
    );
  }

  // 4. ถ้าเจอ แสดงรายละเอียด
  return (
    <div style={{ padding: 20 }}>
      <h1>รายละเอียดงาน</h1>
      <p>ID: {todo.id}</p>
      <p>ข้อความ: {todo.text}</p>
      <p>สถานะ: {todo.done ? "✅ เสร็จแล้ว" : "⏳ ยังไม่เสร็จ"}</p>
      <Link to="/todos">← กลับไปลิสต์งาน</Link>
    </div>
  );
}
```

### ขั้นที่ 2 — เพิ่ม route ใน [src/main.tsx](src/main.tsx)

เพิ่ม import:
```tsx
import { TodoDetail } from "./TodoDetail";
```
แล้วเพิ่ม route นี้ใน `<Routes>` (วางก่อน `path="*"`):
```tsx
<Route path="/todos/:id" element={<TodoDetail />} />
```

### ขั้นที่ 3 — เพิ่มลิงก์ "ดู" ในแต่ละงาน — แก้ [src/TodoItem.tsx](src/TodoItem.tsx)

เพิ่ม import บนสุด:
```tsx
import { Link } from "react-router-dom";
```
แล้วเพิ่มลิงก์ในแต่ละแถว (วางก่อนปุ่ม "ลบ" ใน `<li>`):
```tsx
<Link to={`/todos/${props.todo.id}`}>ดู</Link>
```

---

**เป้าหมาย:** ในลิสต์งาน แต่ละอันมีลิงก์ "ดู" → กดแล้วไปหน้า `/todos/<id>` ที่แสดงรายละเอียดงานนั้น และ URL เปลี่ยนเป็นเลข id จริง ✅

## 💡 อธิบายของใหม่

**1. `useParams()` — ดึงตัวแปรจาก URL**
```tsx
const { id } = useParams();
```
ถ้า route คือ `/todos/:id` และ URL จริงคือ `/todos/5` → `id` จะได้ค่า `"5"`
> ⚠️ ค่าจาก URL เป็น **string เสมอ** (`"5"` ไม่ใช่ `5`) เลยต้องแปลงด้วย `Number(id)` ก่อนเทียบกับ `todo.id` ที่เป็นตัวเลข

**2. Template literal ใน `to`: `` `/todos/${props.todo.id}` ``**
- ใช้ backtick `` ` `` กับ `${}` แทรกค่าตัวแปรลงใน string
- ถ้า `todo.id` เป็น `1718...` ก็ได้ `to="/todos/1718..."`

**3. `.find()` — หา 1 ตัวที่ตรงเงื่อนไข**
- ต่างจาก `.filter()` (คืน array หลายตัว) — `.find()` คืน **ตัวแรกที่เจอตัวเดียว** (หรือ `undefined` ถ้าไม่เจอ)
- เลยต้องเช็ค `if (!todo)` เผื่อหาไม่เจอ (เช่น id มั่ว)

---

ลองทำดูครับ! กด "ดู" ในงานสักอัน แล้วสังเกต URL กับหน้ารายละเอียด 🔍

> 🧪 ทดสอบ: ลองพิมพ์ `http://localhost:5173/todos/999` (id มั่ว) ดู — ควรเจอหน้า "ไม่พบงานนี้"

---

เสร็จแล้วบอกผมครับ! ตอนนี้คุณรู้ React Router ครบทุกส่วนหลักแล้ว 🏆

> 📌 จุดสังเกตสำคัญ: หน้า Detail เราอ่าน localStorage ตรงๆ ซึ่งพอใช้ได้ แต่ทำให้ข้อมูลแยกกันอยู่หลายที่ (TodoApp ก็ถือ, Detail ก็อ่านเอง) — พอแอปใหญ่ขึ้นจะเริ่มยุ่ง ปัญหานี้แก้ด้วย **"การแชร์ state ข้ามหน้า"** (Context API หรือ state management) ซึ่งเป็นบทขั้นสูงที่ดีมากถ้าอยากเรียนต่อ

ถัดไปอยากไป **API จริง (ข้อ 2 เดิม)**, **Context API (แชร์ state)**, หรือ **สรุปทบทวนทั้งหมด** ดีครับ? 😊

