import { StrictMode } from "react";
import { createRoot } from "react-dom/client";
import { BrowserRouter, Routes, Route, NavLink } from "react-router-dom";
import "./index.css";
import { Home } from "./Home";
import { About } from "./About";
import { TodoApp } from "./TodoApp";
import { TodoDetail } from "./TodoDetail";


createRoot(document.getElementById("root")!).render(
  <StrictMode>
    <BrowserRouter>
      {/* แถบเมนู แสดงทุกหน้า */}
      <nav style={{ display: "flex", gap: 16, padding: 16 }}>
        <NavLink to="/" style={({ isActive }) => ({
          fontWeight: isActive ? "bold" : "normal",
          color: isActive ? "#646cff" : "#888",
        })}>
          หน้าแรก
        </NavLink>
        <NavLink to="/todos" style={({ isActive }) => ({
          fontWeight: isActive ? "bold" : "normal",
          color: isActive ? "#646cff" : "#888",
        })}>
          งานของฉัน
        </NavLink>
        <NavLink to="/about" style={({ isActive }) => ({
          fontWeight: isActive ? "bold" : "normal",
          color: isActive ? "#646cff" : "#888",
        })}>
          เกี่ยวกับ
        </NavLink>
      </nav>


      {/* ตรงนี้จะสลับเนื้อหาตาม URL */}
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/todos" element={<TodoApp />} />
        <Route path="/about" element={<About />} />
        <Route path="/todos/:id" element={<TodoDetail />} />

        <Route path="*" element={
          <div style={{ padding: 20 }}>
            <h1>🚧 404 - ไม่พบหน้านี้</h1>
            <p>ขออภัย ไม่มีหน้าที่คุณกำลังหา</p>
            <NavLink to="/">กลับหน้าแรก</NavLink>
          </div>
        } />

      </Routes>
    </BrowserRouter>
  </StrictMode>
);

content.text:
เจอแล้วครับ! 🎯 error อยู่ใน [src/TodoItem.tsx](src/TodoItem.tsx)

## ปัญหา

ที่บรรทัด 29 คุณใช้ `props.todo.id`:
```tsx
<Link to={`/todos/${props.todo.id}`}>ดู</Link>
```

แต่ `type Todo` ในไฟล์นี้ (บรรทัด 3-6) **ยังไม่มี field `id`**:
```tsx
type Todo = {
  text: string;
  done: boolean;
};
```

TypeScript เลยเตือนว่า *"Property 'id' does not exist on type 'Todo'"* — มันไม่รู้จัก `.id` เพราะเราลืมเพิ่มเข้า type ในไฟล์นี้ (ตอนบทที่ 12 เราเพิ่ม `id` แค่ใน `TodoApp.tsx` ลืมไฟล์นี้)

## วิธีแก้

เพิ่ม `id: number;` เข้าไปใน type ครับ:

```tsx
type Todo = {
  id: number;
  text: string;
  done: boolean;
};
```

แก้แค่นี้ error ก็หายครับ ✅

---

## 💡 บทเรียนสำคัญจาก error นี้

สังเกตว่าตอนนี้เรามี `type Todo` **ซ้ำกัน 3 ที่** — ใน `TodoApp.tsx`, `TodoItem.tsx`, และ `TodoDetail.tsx` พอแก้ที่เดียว (เพิ่ม id) อีก 2 ที่เลยไม่ตรงกัน → เกิด bug แบบนี้

**วิธีแก้ที่ดีกว่า (มืออาชีพทำ):** สร้าง type ไว้ **ที่เดียว** แล้ว import ไปใช้ทุกไฟล์

ถ้าสนใจ เดี๋ยวเราทำแบบนี้กันได้ครับ:
1. สร้างไฟล์ `src/types.ts`
2. ย้าย `type Todo` ไปไว้ที่นั่น พร้อม `export`
3. ทุกไฟล์ `import type { Todo } from "./types"`

แบบนี้แก้ที่เดียว ทุกไฟล์อัปเดตตาม ไม่มีทางไม่ตรงกันอีก

