import { useState, useEffect } from "react";
import "./TodoApp.css";
import { TodoItem } from "./TodoItem";
import type { Todo } from "./types";


export function TodoApp() {
    // 1. state เก็บลิสต์งานทั้งหมด (เริ่มต้นเป็น array ว่าง)



    const [todos, setTodos] = useState<Todo[]>(() => {
        const saved = localStorage.getItem("my-todos");
        return saved ? JSON.parse(saved) : [];
    });


    // 2. state เก็บข้อความที่กำลังพิมพ์ในช่อง input
    const [text, setText] = useState("");

    const [filter, setFilter] = useState<"all" | "active" | "done">("all");

    const visibleTodos = todos.filter((todo) => {
        if (filter === "active") return !todo.done;   // เอาเฉพาะที่ยังไม่เสร็จ
        if (filter === "done") return todo.done;      // เอาเฉพาะที่เสร็จแล้ว
        return true;                                  // "all" = เอาทั้งหมด
    });



    useEffect(() => {
        localStorage.setItem("my-todos", JSON.stringify(todos));
    }, [todos]);


    // 3. ฟังก์ชันเพิ่มงานใหม่
    function addTodo() {
        if (text === "") return;
        setTodos([...todos, { id: Date.now(), text: text, done: false }]);
        setText("");
    }


    function deleteTodo(idToDelete: number) {
        setTodos(todos.filter((todo) => todo.id !== idToDelete));
    }

    function toggleTodo(idToToggle: number) {
        setTodos(
            todos.map((todo) =>
                todo.id === idToToggle ? { ...todo, done: !todo.done } : todo
            )
        );
    }


    return (
        <div className="todo-app">
            <h2>📝 Todo List ของฉัน</h2>

            <input
                className="todo-input"
                value={text}
                onChange={(e) => setText(e.target.value)}
                placeholder="พิมพ์งานที่ต้องทำ..."
            />
            <button type="button" className="todo-add-btn" onClick={addTodo}>
                เพิ่ม
            </button>

            <div className="filter-bar">
                <button type="button" onClick={() => setFilter("all")}>ทั้งหมด</button>
                <button type="button" onClick={() => setFilter("active")}>ยังไม่เสร็จ</button>
                <button type="button" onClick={() => setFilter("done")}>เสร็จแล้ว</button>
            </div>


            <ul className="todo-list">
                {visibleTodos.map((todo) => (
                    <TodoItem
                        key={todo.id}
                        todo={todo}
                        onToggle={() => toggleTodo(todo.id)}
                        onDelete={() => deleteTodo(todo.id)}
                    />
                ))}


            </ul>

            <p>ตอนนี้มีงานทั้งหมด: {todos.length} อัน</p>
        </div>
    );

}

content.text:
เยี่ยม ขอบคุณครับ ทีนี้มาแทนที่ logic เดิมด้วยตู้กลางกัน

---

# 📚 บทที่ 21: Context API (ขั้นที่ 3-4)

## ขั้นที่ 3 — แก้ [src/TodoApp.tsx](src/TodoApp.tsx) ให้หยิบจากตู้กลาง

สังเกตว่า `todos`, `addTodo`, `deleteTodo`, `toggleTodo`, และ `useEffect` **ย้ายไปอยู่ใน TodoContext หมดแล้ว** เราเลยลบออกจากที่นี่ได้ แล้วหยิบมาจาก `useTodos()` แทน

แก้ **ส่วนบนของไฟล์** (บรรทัด 1-54) ให้เหลือแค่นี้:

```tsx
import { useState } from "react";
import "./TodoApp.css";
import { TodoItem } from "./TodoItem";
import { useTodos } from "./TodoContext";

export function TodoApp() {
  // หยิบจากตู้กลาง! ไม่ต้องมี state/logic ของ todos ในนี้แล้ว
  const { todos, addTodo, deleteTodo, toggleTodo } = useTodos();

  // state เฉพาะ UI ของหน้านี้ (เก็บไว้เหมือนเดิม)
  const [text, setText] = useState("");
  const [filter, setFilter] = useState<"all" | "active" | "done">("all");

  const visibleTodos = todos.filter((todo) => {
    if (filter === "active") return !todo.done;
    if (filter === "done") return todo.done;
    return true;
  });

  // ปุ่มเพิ่ม: เรียก addTodo จากตู้ แล้วล้างช่อง
  function handleAdd() {
    addTodo(text);
    setText("");
  }
```

> ส่วน `return (...)` ด้านล่าง **เกือบเหมือนเดิม** แค่แก้ปุ่ม "เพิ่ม" จาก `onClick={addTodo}` เป็น `onClick={handleAdd}`:
```tsx
<button type="button" className="todo-add-btn" onClick={handleAdd}>
  เพิ่ม
</button>
```

---

## ขั้นที่ 4 — แก้ [src/TodoDetail.tsx](src/TodoDetail.tsx) ให้หยิบจากตู้กลาง

นี่คือจุดที่แก้ปัญหาเดิม! เปลี่ยนจากอ่าน localStorage เอง → หยิบจากตู้กลาง

แทนที่ **ทั้งไฟล์** ด้วย:

```tsx
import { useParams, Link } from "react-router-dom";
import { useTodos } from "./TodoContext";

export function TodoDetail() {
  const { id } = useParams();
  const { todos } = useTodos(); // หยิบจากตู้กลาง! ไม่อ่าน localStorage แล้ว

  const todo = todos.find((t) => t.id === Number(id));

  if (!todo) {
    return (
      <div style={{ padding: 20 }}>
        <h1>ไม่พบงานนี้ 🤔</h1>
        <Link to="/todos">← กลับไปลิสต์งาน</Link>
      </div>
    );
  }

  return (
    <div style={{ padding: 20 }}>
      <h1>รายละเอียดงาน</h1>
      <p>ID: {todo.id}</p>
      <p>ข้อความ: {todo.text}</p>
      <p>สถานะ: {todo.done ? "✅ เสร็จแล้ว" : "⏳ ยังไม่เสร็จ"}</p>
      <Link to="/todos">← กลับไปลิสต์งาน</Link>
    </div>
  );
}
```

---

**เป้าหมาย:** แอปทำงานเหมือนเดิมเป๊ะ แต่ตอนนี้ `todos` มาจาก **ตู้กลางที่เดียว** ทั้ง TodoApp และ TodoDetail หยิบจากแหล่งเดียวกัน ✅

## 🧪 ทดสอบว่า Context ทำงานจริง (เจ๋งมาก)

1. ไปหน้า "งานของฉัน" เพิ่มงานสัก 2-3 อัน
2. กด "ดู" งานอันนึง → ไปหน้า detail
3. **สังเกต:** ข้อมูลแสดงได้ทันที โดย TodoDetail ไม่ได้อ่าน localStorage เลย — มันหยิบจาก state กลางที่ TodoApp เพิ่งเพิ่มเข้าไป 🎯

## 💡 อธิบายภาพรวม

```
TodoProvider (ตู้กลาง — ถือ todos จริง + logic)
   │  value={{ todos, addTodo, deleteTodo, toggleTodo }}
   ├── TodoApp     →  useTodos()  หยิบ todos + ฟังก์ชันมาใช้
   └── TodoDetail  →  useTodos()  หยิบ todos ตัวเดียวกัน
```

**ข้อดีที่ได้:**
- ✅ ข้อมูลอยู่ที่เดียว (single source of truth) — ไม่กระจัดกระจาย
- ✅ ไม่ต้องส่ง props ผ่านหลายชั้น (ไม่มี prop drilling)
- ✅ เพิ่มหน้าใหม่ที่ต้องใช้ todos? แค่เรียก `useTodos()` ก็ได้เลย

## ⚖️ เมื่อไหร่ควรใช้ Context?

| สถานการณ์ | ใช้อะไร |
|-----------|---------|
| state ใช้ในหน่วยเล็กๆ (เช่น `text` ในฟอร์ม) | `useState` ปกติพอ |
| state ที่หลายหน้า/หลายชั้นต้องใช้ร่วมกัน | **Context** |

> 💡 อย่าเพิ่งเอา Context ไปใส่ทุกอย่างนะครับ — ใช้เมื่อ "หลายที่ต้องแชร์กัน" เท่านั้น ของที่ใช้ในที่เดียว (`text`, `filter`) เก็บเป็น state ปกติดีกว่า

---

ลองทำดูครับ! ถ้าแอปทำงานเหมือนเดิม และ TodoDetail แสดงข้อมูลได้โดยไม่อ่าน localStorage = คุณเข้าใจ Context API แล้ว 🏆

> ⚠️ ถ้าขึ้น error *"useTodos ต้องอยู่ใน TodoProvider"* แปลว่าลืมครอบ `<TodoProvider>` ใน main.tsx (ขั้นที่ 2) — กลับไปเช็คดูครับ

เสร็จแล้วบอกผม! ตอนนี้คุณเรียนครบ concept หลักของ React สมัยใหม่ทั้งหมดแล้วจริงๆ 🎓 ถัดไปผมแนะนำให้ลองทำโปรเจกต์ของตัวเองเพื่อรวมทุกอย่าง — บอกได้เลยถ้าพร้อมครับ 😊

