import { useState, useRef, useEffect } from "react";
import "./TodoApp.css";
import { TodoItem } from "./TodoItem";
import { useTodos } from "./TodoContext";
import { useMemo } from "react";   // เพิ่ม import
import { useCallback } from "react";

export function TodoApp() {
    // หยิบจากตู้กลาง! ไม่ต้องมี state/logic ของ todos ในนี้แล้ว
    const { todos, addTodo, deleteTodo, toggleTodo } = useTodos();

    // state เฉพาะ UI ของหน้านี้ (เก็บไว้เหมือนเดิม)
    const [text, setText] = useState("");
    const [filter, setFilter] = useState<"all" | "active" | "done">("all");

    const inputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        inputRef.current?.focus(); // โฟกัสตอน component โหลดครั้งแรก
    }, []);


    // const visibleTodos = todos.filter((todo) => {
    //     if (filter === "active") return !todo.done;
    //     if (filter === "done") return todo.done;
    //     return true;
    // });


    const visibleTodos = useMemo(() => {
        return todos.filter((todo) => {
            if (filter === "active") return !todo.done;
            if (filter === "done") return todo.done;
            return true;
        });
    }, [todos, filter]);   // 👈 คำนวณใหม่เฉพาะเมื่อ todos หรือ filter เปลี่ยน



    // ปุ่มเพิ่ม: เรียก addTodo จากตู้ แล้วล้างช่อง
    // function handleAdd() {
    //     addTodo(text);
    //     setText("");
    // }
    const handleAdd = useCallback(() => {
        addTodo(text);
        setText("");
    }, [text, addTodo]);



    return (
        <div className="todo-app">
            <h2>📝 Todo List ของฉัน</h2>

            <input
                ref={inputRef}
                className="todo-input"
                value={text}
                onChange={(e) => setText(e.target.value)}
                placeholder="พิมพ์งานที่ต้องทำ..."
            />
            <button type="button" className="todo-add-btn" onClick={handleAdd}>
                เพิ่ม
            </button>

            <div className="filter-bar">
                <button type="button" onClick={() => setFilter("all")}>ทั้งหมด</button>
                <button type="button" onClick={() => setFilter("active")}>ยังไม่เสร็จ</button>
                <button type="button" onClick={() => setFilter("done")}>เสร็จแล้ว</button>
            </div>


            {visibleTodos.length === 0 ? (
                <p className="empty-state">
                    {filter === "all"
                        ? "🎉 ยังไม่มีงาน เพิ่มงานแรกของคุณเลย!"
                        : "ไม่มีงานในหมวดนี้"}
                </p>
            ) : (
                <ul className="todo-list">
                    {visibleTodos.map((todo) => (
                        <TodoItem
                            key={todo.id}
                            todo={todo}
                            onToggle={() => toggleTodo(todo.id)}
                            onDelete={() => deleteTodo(todo.id)}
                        />
                    ))}
                </ul>
            )}


            <p>ตอนนี้มีงานทั้งหมด: {todos.length} อัน</p>
        </div>
    );

}

