import { useParams, Link } from "react-router-dom";
import { useFetch } from "./useFetch";

type Post = {
  id: number;
  title: string;
  body: string;
};

export function PostDetail() {
  const { id } = useParams(); // ดึง id จาก URL

  // เอา id ต่อท้าย url → ขอโพสต์ตัวเดียวจาก API
  const { data: post, loading, error } = useFetch<Post>(
    `https://jsonplaceholder.typicode.com/posts/${id}`
  );

  if (loading) return <p style={{ padding: 20 }}>⏳ กำลังโหลด...</p>;
  if (error) return <p style={{ padding: 20 }}>❌ {error}</p>;

  return (
    <div style={{ padding: 20 }}>
      <Link to="/posts">← กลับไปลิสต์โพสต์</Link>
      <h1>{post?.title}</h1>
      <p>{post?.body}</p>
      <p style={{ color: "#888" }}>โพสต์ ID: {post?.id}</p>
    </div>
  );
}

import { useParams, Link } from "react-router-dom";

import { useTodos } from "./TodoContext";


export function TodoDetail() {
  // 1. ดึง id ออกจาก URL
  const { id } = useParams();

  // 2. โหลด todos จาก localStorage แล้วหาตัวที่ id ตรง
  const { todos } = useTodos(); // หยิบจากตู้กลาง! ไม่อ่าน localStorage แล้ว

  const todo = todos.find((t) => t.id === Number(id));

  // 3. ถ้าหาไม่เจอ
  if (!todo) {
    return (
      <div style={{ padding: 20 }}>
        <h1>ไม่พบงานนี้ 🤔</h1>
        <Link to="/todos">← กลับไปลิสต์งาน</Link>
      </div>
    );
  }

  // 4. ถ้าเจอ แสดงรายละเอียด
  return (
    <div style={{ padding: 20 }}>
      <h1>รายละเอียดงาน</h1>
      <p>ID: {todo.id}</p>
      <p>ข้อความ: {todo.text}</p>
      <p>สถานะ: {todo.done ? "✅ เสร็จแล้ว" : "⏳ ยังไม่เสร็จ"}</p>
      <Link to="/todos">← กลับไปลิสต์งาน</Link>
    </div>
  );
}

